import type { ReactNode } from "react";

/**
 * Dependency-free icon set for the docs site. Monochrome, 24x24, `currentColor`
 * so each icon adapts to the surrounding text color on both the pure-white and
 * pitch-black canvases. Used two ways:
 *
 *   1. Section-tab + sidebar icons, resolved from the string `icon` field in
 *      `meta.json` (folders) or page frontmatter, via the `icons` registry
 *      wired into `lib/source.ts`.
 *   2. `<Card icon={<ShieldCheckIcon />}>` routing grids, imported directly in
 *      MDX.
 *
 * Line-icon geometry follows the Lucide set (ISC-licensed, stroke-based). The
 * framework brand marks are fill-based glyphs from simple-icons (CC0 1.0);
 * trademarks remain the property of their respective owners.
 */

interface IconProps {
  readonly className?: string;
}

function Icon({ children, className }: { children: ReactNode; className?: string }) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth={1.75}
      strokeLinecap="round"
      strokeLinejoin="round"
      aria-hidden="true"
      className={className}
    >
      {children}
    </svg>
  );
}

function BrandIcon({ children, className }: { children: ReactNode; className?: string }) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox="0 0 24 24"
      fill="currentColor"
      aria-hidden="true"
      className={className}
    >
      {children}
    </svg>
  );
}

